331	export function setProjectExpanded(
332	  state: AppState,
333	  projectId: Project["id"],
334	  expanded: boolean,
335	): AppState {
336	  let changed = false;
337	  const projects = state.projects.map((p) => {
338	    if (p.id !== projectId || p.expanded === expanded) return p;
339	    changed = true;
340	    return { ...p, expanded };
341	  });
342	  return changed ? { ...state, projects } : state;
343	}
344	
345	export function setError(state: AppState, threadId: ThreadId, error: string | null): AppState {
346	  const threads = updateThread(state.threads, threadId, (t) => {
347	    if (t.error === error) return t;
348	    return { ...t, error };
349	  });
350	  return threads === state.threads ? state : { ...state, threads };
351	}
352	
353	export function setThreadBranch(
354	  state: AppState,
355	  threadId: ThreadId,
356	  branch: string | null,
357	  worktreePath: string | null,
358	): AppState {
359	  const threads = updateThread(state.threads, threadId, (t) => {
360	    if (t.branch === branch && t.worktreePath === worktreePath) return t;
361	    const cwdChanged = t.worktreePath !== worktreePath;
362	    return {
363	      ...t,
364	      branch,
365	      worktreePath,
366	      ...(cwdChanged ? { session: null } : {}),
367	    };
368	  });
369	  return threads === state.threads ? state : { ...state, threads };
370	}
