import { useCallback, useEffect, useSyncExternalStore } from "react";
import { type Theme, getTheme, listThemes } from "@t3tools/shared/themes";

export type { Theme };

const STORAGE_KEY = "t3code:theme";
const DEFAULT_THEME_ID = "t3-dark";

/** Map legacy "light" / "dark" / "system" values to the new named theme IDs. */
function migrateLegacyValue(raw: string): string {
  if (raw === "light") return "t3-light";
  if (raw === "dark") return "t3-dark";
  if (raw === "system") {
    const prefersDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
    return prefersDark ? "t3-dark" : "t3-light";
  }
  return raw;
}

function getStored(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (!raw) return DEFAULT_THEME_ID;
  return migrateLegacyValue(raw);
}

function applyTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Keep Tailwind dark-mode utilities working across all existing components.
  document.documentElement.classList.toggle("dark", theme.isDark);

  // Inject theme colors as CSS custom properties — inline styles take highest
  // specificity and override both :root and .dark variant rules in index.css.
  const root = document.documentElement;
  root.style.setProperty("--background", theme.colors.background);
  root.style.setProperty("--foreground", theme.colors.foreground);
  // Accent drives primary, ring, and accent in the Tailwind palette.
  root.style.setProperty("--accent", theme.colors.accent);
  root.style.setProperty("--primary", theme.colors.accent);
  root.style.setProperty("--ring", theme.colors.accent);
  // New semantic vars for editor surfaces (consumed by future components).
  root.style.setProperty("--sidebar-bg", theme.colors.sidebar);
  root.style.setProperty("--editor-bg", theme.colors.editor);
  root.style.setProperty("--terminal-bg", theme.colors.terminal);
  root.style.setProperty("--status-bar-bg", theme.colors.statusBar);
  // Typography
  root.style.setProperty("--theme-font-family", theme.fontFamily);
  root.style.setProperty("--theme-font-size", `${theme.fontSize}px`);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash.
applyTheme(getTheme(getStored()));

// ---------------------------------------------------------------------------
// Module-level external store (mirrors the pattern of the original useTheme).
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let lastThemeId: string | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSnapshot(): Theme {
  const id = getStored();
  if (lastThemeId === id) {
    // Return a stable reference to avoid unnecessary re-renders.
    return getTheme(id);
  }
  lastThemeId = id;
  return getTheme(id);
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for storage changes from other tabs.
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getTheme(getStored()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------

export function useTheme() {
  const theme = useSyncExternalStore(subscribe, getSnapshot);

  const resolvedTheme: "light" | "dark" = theme.isDark ? "dark" : "light";

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id);
    localStorage.setItem(STORAGE_KEY, id);
    applyTheme(next, true);
    emitChange();
  }, []);

  const availableThemes = listThemes();

  // Keep DOM in sync on mount/change.
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, availableThemes, resolvedTheme } as const;
}

