import { useTheme } from "../hooks/useTheme";

/**
 * Self-contained theme selector component. Renders a radio-group of all
 * available themes with color swatches, using the same visual style as the
 * existing settings radio buttons.
 */
export function ThemeSelector() {
  const { theme, setTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
      {availableThemes.map((option) => {
        const selected = theme.id === option.id;
        return (
          <button
            key={option.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center justify-between rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(option.id)}
          >
            <span className="flex min-w-0 flex-1 items-center gap-3">
              {/* Color swatches */}
              <span className="flex shrink-0 items-center gap-1" aria-hidden="true">
                <span
                  className="h-3 w-3 rounded-full border border-black/10"
                  style={{ backgroundColor: option.colors.background }}
                />
                <span
                  className="h-3 w-3 rounded-full border border-black/10"
                  style={{ backgroundColor: option.colors.foreground }}
                />
                <span
                  className="h-3 w-3 rounded-full border border-black/10"
                  style={{ backgroundColor: option.colors.accent }}
                />
              </span>
              <span className="text-sm font-medium">{option.name}</span>
            </span>

            {selected ? (
              <span className="ml-3 shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Selected
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

