export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

export interface Theme {
  readonly id: string;
  readonly name: string;
  /** Whether this theme requires the `.dark` CSS class for Tailwind dark-mode utilities. */
  readonly isDark: boolean;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  /** Base font size in pixels. */
  readonly fontSize: number;
}

const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    isDark: true,
    colors: {
      background: "color-mix(in srgb, oklch(0.10 0 0) 95%, white)",
      foreground: "oklch(0.90 0 0)",
      accent: "oklch(0.588 0.217 264)",
      sidebar: "oklch(0.11 0 0)",
      editor: "oklch(0.09 0 0)",
      terminal: "oklch(0.08 0 0)",
      statusBar: "oklch(0.13 0 0)",
    },
    fontFamily: '"DM Sans", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    isDark: false,
    colors: {
      background: "#ffffff",
      foreground: "oklch(0.37 0 0)",
      accent: "oklch(0.488 0.217 264)",
      sidebar: "oklch(0.97 0 0)",
      editor: "#ffffff",
      terminal: "oklch(0.97 0 0)",
      statusBar: "oklch(0.95 0 0)",
    },
    fontFamily: '"DM Sans", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    isDark: true,
    colors: {
      background: "oklch(0.07 0.02 264)",
      foreground: "oklch(0.92 0.015 264)",
      accent: "oklch(0.65 0.25 264)",
      sidebar: "oklch(0.06 0.02 264)",
      editor: "oklch(0.05 0.015 264)",
      terminal: "oklch(0.05 0.02 264)",
      statusBar: "oklch(0.09 0.03 264)",
    },
    fontFamily: '"DM Sans", system-ui, sans-serif',
    fontSize: 14,
  },
];

/** Return all built-in themes. */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

/**
 * Return the theme with the given id, or the default theme (t3-dark) if not found.
 */
export function getTheme(id: string): Theme {
  return BUILT_IN_THEMES.find((t) => t.id === id) ?? BUILT_IN_THEMES[0]!;
}

